file.content:
.chat-tab {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  color: var(--text-muted);
  cursor: pointer;
  white-space: nowrap;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
  border-bottom: 2px solid transparent;
  transition: all 0.15s;
  flex-shrink: 0;
}

.chat-tab:hover { color: var(--text-secondary); }
.chat-tab.active {
  color: var(--text-primary);
  background: var(--bg-surface);
  font-weight: 600;
  border-bottom: 3px solid var(--accent, #FF4D00);
}

.chat-tab-close {
  font-size: 14px;
  opacity: 0.4;
  cursor: pointer;
}
.chat-tab-close:hover { opacity: 1; }

.chat-panel-controls {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.chat-cost {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 8px;
  border: 1px solid var(--border);
  border-radius: 3px;
  white-space: nowrap;
}
.chat-cost.context-warn {
  color: #e5c07b;
  border-color: #e5c07b44;
}
.chat-cost.context-critical {
  color: #e06c75;
  border-color: #e06c7544;
}


.chat-panel-close {
  font-size: 18px;
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  padding: 4px 8px;
}
.chat-panel-close:hover { color: var(--text-primary); }

/* Chat body: sidebar + messages side by side */
.chat-body {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* Turn navigation sidebar */
.chat-turn-sidebar {
  width: 220px;
  flex-shrink: 0;
  border-right: 1px solid var(--border, #333);
  background: var(--bg-secondary, #1a1a1a);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}
.chat-turn-sidebar.hidden,
.chat-turn-sidebar.collapsed {
  display: none;
}

.turn-sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 10px;
  border-bottom: 1px solid var(--border, #333);
  flex-shrink: 0;
}
.turn-sidebar-title {
  font-family: var(--font-heading, sans-serif);
  font-size: 11px;
  text-transform: uppercase;
  color: var(--text-muted);
  letter-spacing: 0.5px;
}
.turn-counter {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-muted);
}

.turn-list {
  flex: 1;
  overflow-y: auto;
  padding: 4px 0;
}

.turn-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 6px 10px;
  cursor: pointer;
  border-left: 2px solid transparent;
}
.turn-item:hover {
  background: var(--bg-hover);
}
.turn-item.active {
  border-left-color: var(--accent, #FF4D00);
  background: var(--accent-dim);
}

.turn-label {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--accent, #FF4D00);
  min-width: 18px;
  flex-shrink: 0;
  font-weight: 700;
}

.turn-preview {
  font-size: var(--font-size-sm);
  font-weight: 400;
  color: var(--text-muted);
  line-height: 1.4;
  overflow: hidden;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}

.turn-shortcuts {
  padding: 6px 10px;
  font-size: 10px;
  color: var(--text-muted);
  border-top: 1px solid var(--border, #333);
  text-align: center;
  flex-shrink: 0;
}

/* Turn highlight flash when jumping */
.chat-bubble.user.turn-highlight {
  outline: 2px solid var(--accent, #FF4D00);
  outline-offset: 2px;
  transition: outline-color 1.5s ease-out;
}

/* Chat messages area */
.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 0;
  position: relative;
}

.chat-tab-container {
  display: none;
  padding: 16px;
}
.chat-tab-container.active {
  display: block;
}

/* User bubble */
.chat-bubble.user {
  background: var(--accent, #FF4D00);
  color: #fff;
  padding: 10px 16px;
  border-radius: 16px 16px 4px 16px;
  margin: 12px 0 12px auto;
  max-width: 80%;
  width: fit-content;
  font-size: 14px;
  line-height: 1.5;
  word-wrap: break-word;
  white-space: pre-wrap;
  box-shadow: 0 1px 3px rgba(255, 77, 0, 0.2);
}

/* Assistant bubble */
.chat-bubble.assistant {
  background: var(--bg-surface, #222);
  color: var(--text-primary, #eee);
  padding: 14px 18px;
  border-radius: 16px 16px 16px 4px;
  margin: 12px auto 12px 0;
  max-width: 75%;
  width: fit-content;
  font-size: 14px;
  line-height: 1.6;
  border: 1px solid var(--border-light);
}

/* Markdown content inside assistant bubble */
.chat-md-content h1, .chat-md-content h2, .chat-md-content h3 {
  margin: 12px 0 6px;
  font-family: var(--font-heading, 'Archivo Black', sans-serif);
}
.chat-md-content h1 { font-size: 18px; }
.chat-md-content h2 { font-size: 16px; }
.chat-md-content h3 { font-size: 14px; }

.chat-md-content p { margin: 6px 0; }

.chat-md-content pre {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  border-radius: 6px;
  padding: 10px 12px;
  overflow-x: auto;
  font-size: 13px;
  margin: 8px 0;
}

.chat-md-content code {
  font-family: var(--font-mono, 'JetBrains Mono', monospace);
  font-size: 13px;
}

.chat-md-content :not(pre) > code {
  background: var(--bg-code-inline);
  padding: 1px 5px;
  border-radius: 3px;
}

.chat-md-content table {
  border-collapse: collapse;
  margin: 8px 0;
  font-size: 13px;
}
.chat-md-content th, .chat-md-content td {
  border: 1px solid var(--border-table);
  padding: 4px 10px;
  text-align: left;
}
.chat-md-content th { background: var(--bg-table-header); }

.chat-md-content ul, .chat-md-content ol {
  padding-left: 20px;
  margin: 6px 0;
}

.chat-md-content blockquote {
  border-left: 3px solid var(--accent, #FF4D00);
  margin: 8px 0;
  padding: 4px 12px;
  color: var(--text-secondary);
}

.chat-md-content a { color: var(--accent, #FF4D00); }

/* Thinking block */
.chat-thinking {
  margin: 6px 0;
  font-size: 13px;
  color: var(--text-muted);
  border-left: 2px solid var(--border);
  padding-left: 10px;
}
.chat-thinking summary {
  cursor: pointer;
  font-style: italic;
  color: var(--text-muted);
}
.chat-thinking-content {
  white-space: pre-wrap;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  margin-top: 4px;
  max-height: 200px;
  overflow-y: auto;
}

/* Tool call cards */
.chat-tool-card {
  margin: 6px 0;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--bg-surface);
  font-size: 13px;
  border-left: 3px solid var(--border);
  transition: border-color 150ms ease;
}

.chat-tool-card:has(.chat-tool-status.completed) {
  border-left-color: #48bb78;
}

.chat-tool-card:has(.chat-tool-status.in_progress) {
  border-left-color: var(--accent);
}

.chat-tool-card:has(.chat-tool-status.failed) {
  border-left-color: #e53e3e;
}

.chat-tool-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px;
  cursor: pointer;
  list-style: none;
}
.chat-tool-header::-webkit-details-marker { display: none; }

.chat-tool-icon { font-size: 14px; }

.chat-tool-title {
  flex: 1;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  color: var(--text-primary);
}

.chat-tool-path {
  font-family: var(--font-mono, monospace);
  color: var(--text-muted);
  font-size: 11px;
}

.chat-tool-status {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  padding: 1px 6px;
  border-radius: 3px;
  text-transform: uppercase;
}
.chat-tool-status.pending { color: var(--text-muted); background: var(--bg-hover); }
.chat-tool-status.in_progress { color: var(--accent, #FF4D00); background: rgba(255,77,0,0.1); }
.chat-tool-status.completed { color: #4a4; background: rgba(68,170,68,0.1); }
.chat-tool-status.failed { color: #d44; background: rgba(221,68,68,0.1); }

/* Collapsed group of completed tool calls */
.chat-tool-group {
  margin: 6px 0;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--bg-surface);
  font-size: 13px;
}
.chat-tool-group > summary {
  padding: 6px 10px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  color: var(--text-muted);
  list-style: none;
}
.chat-tool-group > summary::-webkit-details-marker { display: none; }

.chat-tool-body {
  padding: 0 10px 8px;
}

.chat-tool-output {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  border-radius: 4px;
  padding: 8px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  white-space: pre-wrap;
  word-break: break-all;
  max-height: 300px;
  overflow-y: auto;
  color: var(--text-secondary);
  margin: 4px 0;
}

/* Diff display */
.chat-diff {
  margin: 4px 0;
}
.chat-diff-header {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 0;
}
.chat-diff-content {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  border-radius: 4px;
  padding: 8px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  white-space: pre-wrap;
  max-height: 300px;
  overflow-y: auto;
  color: var(--text-secondary);
}

/* Plan checklist */
.chat-plan {
  margin: 8px 0;
  padding: 8px 12px;
  background: var(--bg-hover);
  border-radius: 6px;
  border: 1px solid var(--border);
}
.chat-plan-title {
  font-family: var(--font-heading, sans-serif);
  font-size: 12px;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 4px;
}
.chat-plan ul {
  list-style: none;
  padding: 0;
  margin: 0;
}
.chat-plan-entry {
  padding: 2px 0;
  font-size: 13px;
  color: var(--text-secondary);
}
.chat-plan-entry.completed { color: #4a4; }
.chat-plan-entry.failed { color: #d44; }
.chat-plan-icon { margin-right: 6px; }

/* System messages */
.chat-system-msg {
  text-align: center;
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  padding: 6px;
  font-family: var(--font-mono, monospace);
  font-style: italic;
}

.chat-terminated {
  color: #e06c75;
  border: 1px solid #e06c7533;
  border-radius: 4px;
  padding: 10px;
  margin: 8px 0;
}

/* Info banner */
.chat-info-banner {
  background: rgba(255,200,0,0.08);
  border: 1px solid rgba(255,200,0,0.2);
  border-radius: 6px;
  padding: 8px 12px;
  font-size: 13px;
  color: var(--text-secondary);
  margin: 8px 0;
}

/* Auth banner */
.chat-auth-banner {
  background: rgba(255,77,0,0.08);
  border: 1px solid rgba(255,77,0,0.2);
  border-radius: 6px;
  padding: 12px;
  margin: 8px 0;
  text-align: center;
}
.chat-auth-text {
  font-size: 13px;
  color: var(--accent);
  margin-bottom: 8px;
}
.chat-auth-retry {
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  padding: 4px 16px;
  background: var(--accent, #FF4D00);
  color: #fff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}
.chat-auth-retry:hover { opacity: 0.8; }

/* Image preview strip above input */
.chat-image-preview {
  display: none;
  flex-shrink: 0;
  gap: 8px;
  padding: 8px 12px 0;
  background: var(--bg-secondary, #1a1a1a);
  border-top: 1px solid var(--border, #333);
  overflow-x: auto;
}
.chat-image-preview.active {
  display: flex;
}
.image-preview-thumb {
  position: relative;
  flex-shrink: 0;
}
.image-preview-thumb img {
  height: 64px;
  max-width: 120px;
  object-fit: cover;
  border-radius: 4px;
  border: 1px solid var(--border);
}
.image-preview-remove {
  position: absolute;
  top: -4px;
  right: -4px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: none;
  background: var(--text-muted);
  color: var(--bg-primary);
  font-size: 12px;
  line-height: 1;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
}
.image-preview-remove:hover {
  background: var(--accent);
}

/* Images inside user bubbles */
.chat-bubble-images {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 6px;
}
.chat-bubble-img {
  max-width: 300px;
  max-height: 200px;
  border-radius: 6px;
  object-fit: contain;
}

/* Input bar */
.chat-input-bar {
  display: flex;
  align-items: flex-end;
  gap: 8px;
  padding: 8px 12px;
  background: var(--bg-secondary, #1a1a1a);
  border-top: 1px solid var(--border, #333);
  flex-shrink: 0;
}

.chat-input {
  flex: 1;
  background: var(--bg-surface, #222);
  color: var(--text-primary, #eee);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 8px 12px;
  font-family: var(--font-body, 'Archivo', sans-serif);
  font-size: 14px;
  resize: none;
  outline: none;
  max-height: 150px;
  line-height: 1.4;
}
.chat-input:focus { border-color: var(--accent, #FF4D00); }
.chat-input:disabled { opacity: 0.5; }

.chat-send-btn {
  width: 36px;
  height: 36px;
  background: var(--accent, #FF4D00);
  color: #fff;
  border: none;
  border-radius: 50%;
  font-size: 18px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.chat-send-btn:hover { opacity: 0.8; }
.chat-send-btn:disabled { opacity: 0.3; cursor: default; }

.chat-stop-btn {
  width: 36px;
  height: 36px;
  background: #e53e3e;
  color: #fff;
  border: none;
  border-radius: 50%;
  font-size: 14px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: background 150ms ease;
}
.chat-stop-btn:hover { background: #c53030; }
.chat-stop-btn.hidden { display: none; }

body.chat-open .content {
  padding-bottom: calc(50vh + 24px);
}

/* ===== Responsive ===== */

@media (max-width: 800px) {
  .header,
  .content {
    padding-left: 16px;
    padding-right: 16px;
  }

  .header-title {
    font-size: 20px;
  }

  .session-row {
    grid-template-columns: 10px 1fr auto;
    gap: 8px;
  }

  .status-label,
  .time-ago {
    display: none;
  }

  .chat-bubble.assistant {
    max-width: 90%;
  }
}

/* ===== Dark Mode ===== */

/* ===== Dark Mode ===== */
/*
 * Theme is controlled by JS adding .dark to <html>.
 * JS sets .dark based on: localStorage preference, OS media query, or toggle.
 * Variables and component overrides both use the single .dark selector.
 */

html.dark {
  --bg-primary: #0e0e0e;
  --bg-secondary: #181818;
  --bg-hover: #222222;
  --bg-surface: #1e1e1e;

  --text-primary: #EEEEEE;
  --text-secondary: #BBBBBB;
  --text-muted: #777777;

  --border: #2e2e2e;
  --border-light: #252525;

  --accent-dim: rgba(255, 77, 0, 0.15);

  --bg-code: #0a0a0a;
  --border-code: #2e2e2e;
  --bg-code-inline: rgba(255, 255, 255, 0.08);
  --bg-table-header: rgba(255, 255, 255, 0.05);
  --border-table: #444444;

  --status-done: #888888;
  --status-likely-done: #666666;

  --badge-claude: #DDDDDD;
  --badge-codex: #AAAAAA;
}

html.dark .header { box-shadow: 0 1px 6px rgba(0, 0, 0, 0.3); border-bottom-color: #222; }
html.dark .repo-group { box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2); }
html.dark .repo-group:hover { box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3); }
html.dark .status-label.done { background: rgba(255, 255, 255, 0.06); border-color: rgba(255, 255, 255, 0.08); }
html.dark .status-label.likely-done { background: rgba(255, 255, 255, 0.04); border-color: rgba(255, 255, 255, 0.06); }
html.dark .status-label.waiting-for-input { color: #ffd700; background: rgba(255, 215, 0, 0.15); }
html.dark .search-overlay { background: rgba(0, 0, 0, 0.6); }
html.dark .search-box { box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5), 0 0 0 1px rgba(255, 255, 255, 0.05); }

