/* ===== Chat Dock (minimized windows) ===== */

.chat-dock {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  z-index: 99;
  pointer-events: auto;
}

.chat-dock.hidden {
  display: none;
}

.chat-dock-pill {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 12px;
  border: 1px solid var(--border);
  border-radius: 16px;
  background: var(--bg-surface);
  cursor: pointer;
  transition: all 150ms ease;
  max-width: 200px;
}
.chat-dock-pill:hover {
  border-color: var(--accent);
  background: var(--accent-dim);
}

.chat-dock-pill .dock-status {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-muted);
  flex-shrink: 0;
}
.chat-dock-pill.streaming .dock-status {
  background: var(--accent);
  animation: pulse-dot 2s ease-in-out infinite;
}

.chat-dock-pill .dock-title {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-dock-pill .dock-unread {
  font-family: var(--font-mono, monospace);
  font-size: 9px;
  font-weight: 700;
  min-width: 16px;
  height: 16px;
  line-height: 16px;
  text-align: center;
  background: var(--accent);
  color: #fff;
  border-radius: 8px;
  flex-shrink: 0;
}

.chat-dock-pill .dock-close {
  font-size: 12px;
  color: var(--text-muted);
  cursor: pointer;
  opacity: 0;
  transition: opacity 100ms ease;
  padding: 0 2px;
  background: none;
  border: none;
}
.chat-dock-pill:hover .dock-close { opacity: 1; }
.chat-dock-pill .dock-close:hover { color: var(--accent); }

/* Resize handles */
.chat-resize-handle {
  position: absolute;
  z-index: 2;
}
.chat-resize-handle.right {
  top: 0; right: -3px; bottom: 0; width: 6px;
  cursor: ew-resize;
}
.chat-resize-handle.bottom {
  left: 0; right: 0; bottom: -3px; height: 6px;
  cursor: ns-resize;
}
.chat-resize-handle.corner {
  right: -3px; bottom: -3px; width: 12px; height: 12px;
  cursor: nwse-resize;
}

